import React from 'react';
import { ChakraProvider, Box, Button, Flex, Heading } from '@chakra-ui/react';
import { BrowserRouter as Router, Routes, Route, Link, useNavigate } from 'react-router-dom';
import Login from './components/Login';
import Signup from './components/Signup';
import QueueTaskTracker from './components/QueueTaskTracker';
import UserDashboard from './components/UserDashboard';

function App() {
  const [isAuthenticated, setIsAuthenticated] = React.useState(!!localStorage.getItem('authToken'));
  const navigate = useNavigate();

  // Log out function
  const handleLogout = () => {
    localStorage.removeItem('authToken');
    setIsAuthenticated(false);
    navigate('/');
  };

  return (
    <ChakraProvider>
      <Router>
        {/* Header Component */}
        <Box as="header" p={4} bg="teal.500" color="white">
          <Flex alignItems="center" justifyContent="space-between">
            <Heading as="h1" size="lg">
              Task Tracker App
            </Heading>
            <Flex>
              {!isAuthenticated ? (
                <>
                  <Button as={Link} to="/" colorScheme="teal" variant="outline" mr={4}>
                    Log In
                  </Button>
                  <Button as={Link} to="/signup" colorScheme="teal" variant="solid">
                    Sign Up
                  </Button>
                </>
              ) : (
                <>
                  <Button as={Link} to="/task-tracker" colorScheme="teal" variant="outline" mr={4}>
                    Task Tracker
                  </Button>
                  <Button as={Link} to="/dashboard" colorScheme="teal" variant="outline" mr={4}>
                    Dashboard
                  </Button>
                  <Button colorScheme="red" onClick={handleLogout}>
                    Log Out
                  </Button>
                </>
              )}
            </Flex>
          </Flex>
        </Box>

        {/* Routes Setup */}
        <Box as="main" p={4}>
          <Routes>
            <Route path="/" element={<Login setIsAuthenticated={setIsAuthenticated} />} />
            <Route path="/signup" element={<Signup />} />
            <Route path="/task-tracker" element={<QueueTaskTracker />} />
            <Route path="/dashboard" element={<UserDashboard />} />
          </Routes>
        </Box>
      </Router>
    </ChakraProvider>
  );
}

export default App;
